	Command    []string          `json:"command"`
	Timeout    int               `json:"timeout,omitempty"`
	WorkingDir string            `json:"workingDir,omitempty"`
	Env        map[string]string `json:"env,omitempty"`
}

type ExecuteResponse struct {
	Stdout    string `json:"stdout"`
	Stderr    string `json:"stderr"`
	ExitCode  int    `json:"exitCode"`
	Duration  int64  `json:"duration"`
	StartTime int64  `json:"startTime"`
	EndTime   int64  `json:"endTime"`
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(400, gin.H{"error": "command is required"})
		return
	}

	timeout := time.Duration(req.Timeout) * time.Second
	if timeout == 0 {
		timeout = DefaultTimeout
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	env := os.Environ()
	for k, v := range req.Env {
		env = append(env, k+"="+v)
	}
	cmd.Env = env

	if req.WorkingDir != "" {
		cmd.Dir = req.WorkingDir
	}

	startTime := time.Now()
	stdout, err := cmd.Output()
	endTime := time.Now()

	resp := ExecuteResponse{
		StartTime: startTime.Unix(),
		EndTime:   endTime.Unix(),
		Duration:  endTime.Sub(startTime).Milliseconds(),
	}

	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			resp.ExitCode = exitErr.ExitCode()
			resp.Stderr = string(exitErr.Stderr)
		} else if ctx.Err() == context.DeadlineExceeded {
			resp.ExitCode = TimeoutExitCode
			resp.Stderr = "command timed out"
		} else {
			resp.ExitCode = 1
			resp.Stderr = err.Error()
		}
	} else {
		resp.ExitCode = 0
		resp.Stdout = string(stdout)
	}

	c.JSON(200, resp)
}

