	"golang.org/x/net/http2/h2c"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager SessionManager
	storeClient    store.Store
	httpTransport  *http.Transport
	jwtManager     *JWTManager
}

func NewServer(config *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	}

	engine := gin.New()
	engine.Use(gin.Recovery())

	storeClient := store.Storage()

	jwtManager := NewJWTManager()

	s := &Server{
		config:      config,
		engine:      engine,
		storeClient: storeClient,
		jwtManager:  jwtManager,
		httpTransport: &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}

	s.sessionManager = NewSessionManager(storeClient)
	s.setupRoutes()

	return s
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1/namespaces/:namespace")
	{
		v1.GET("/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.POST("/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.PUT("/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.DELETE("/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)

		v1.GET("/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		v1.POST("/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		v1.PUT("/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		v1.DELETE("/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	}
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	h2s := &http2.Server{}
	handler := h2c.NewHandler(s.engine, h2s)

	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           handler,
		ReadHeaderTimeout: 10 * time.Second,
	}

	log.Printf("Starting Router on %s", addr)

	if s.config.EnableTLS {
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop() error {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func RunServer(config *Config) error {
	server := NewServer(config)

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		if err := server.Start(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("Failed to start server: %v", err)
		}
	}()

	<-sigChan
	return server.Stop()
}

