	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

const (
	IdentitySecretName = "picod-router-identity"
	PrivateKeyDataKey  = "private.pem"
	PublicKeyDataKey   = "public.pem"
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() *JWTManager {
	privateKey, _ := rsa.GenerateKey(rand.Reader, 2048)

	jm := &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}

	return jm
}

func (jm *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	tokenClaims := jwt.MapClaims{
		"exp": time.Now().Add(5 * time.Minute).Unix(),
		"iat": time.Now().Unix(),
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		tokenClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(jm.privateKey),
			}),
			PublicKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "PUBLIC KEY",
				Bytes: x509.MarshalPKIXPublicKey(jm.publicKey),
			}),
		},
	}

	_, err := clientset.CoreV1().Secrets(namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if k8serrors.IsAlreadyExists(err) {
			return jm.loadExistingKey(ctx, clientset, namespace)
		}
		return err
	}

	return nil
}

func (jm *JWTManager) loadExistingKey(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret, err := clientset.CoreV1().Secrets(namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		return err
	}

	privateBlock, _ := pem.Decode(secret.Data[PrivateKeyDataKey])
	if privateBlock == nil {
		return nil
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateBlock.Bytes)
	if err != nil {
		return err
	}

	publicBlock, _ := pem.Decode(secret.Data[PublicKeyDataKey])
	if publicBlock == nil {
		return nil
	}

	publicKey, err := x509.ParsePKIXPublicKey(publicBlock.Bytes)
	if err != nil {
		return err
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey.(*rsa.PublicKey)

	return nil
}

